def predict_next_frame(frame, action, xy=None):
    """
    Deterministic predictor based on all observed transitions.

    ACTION1 : clear (0,4) and (0,5).
    ACTION3 : swap 12↔9 in the 4×4 block at rows 36‑39,
              cols 24‑27 (12→9) and cols 44‑47 (9→12);
              also clear (63,14) and (63,15).
    ACTION5 : clear the two cells at the bottom row that are 14.
              In all examples these are (63,11)&(63,12) or (63,10)&(63,??)
              – we simply clear any 14s in the last row.
    ACTION4 : swap 9↔12 in a 4×4 block at rows 24‑27,
              cols 16‑19 (9→12) and cols 36‑39 (12→9);
              also clear (0,19) and (0,20).

    All other actions leave the frame unchanged.
    """
    # deep copy
    new_frame = [row[:] for row in frame]

    if action == "ACTION1":
        new_frame[0][4] = 0
        new_frame[0][5] = 0

    elif action == "ACTION3":
        for r in range(36, 40):
            for c in range(24, 28):          # 12 → 9
                if new_frame[r][c] == 12:
                    new_frame[r][c] = 9
            for c in range(44, 48):          # 9 → 12
                if new_frame[r][c] == 9:
                    new_frame[r][c] = 12
        new_frame[63][14] = 0
        new_frame[63][15] = 0

    elif action == "ACTION5":
        # clear any 14s in the bottom row (row index 63)
        for c in range(64):
            if new_frame[63][c] == 14:
                new_frame[63][c] = 0

    elif action == "ACTION4":
        for r in range(24, 28):
            for c in range(16, 20):          # 9 → 12
                if new_frame[r][c] == 9:
                    new_frame[r][c] = 12
            for c in range(36, 40):          # 12 → 9
                if new_frame[r][c] == 12:
                    new_frame[r][c] = 9
        new_frame[0][19] = 0
        new_frame[0][20] = 0

    return new_frame
